1932	func (s *Server) handleAgentWorkers(w http.ResponseWriter, r *http.Request) {
1933		// Scoped/singleton: return workers for just the resolved project.
1934		if _, ok := projectFromContext(r.Context()); ok {
1935			m := s.workerManagerForRequest(r)
1936			recs, err := m.List()
1937			if err != nil {
1938				writeJSON(w, http.StatusOK, []WorkerRecord{})
1939				return
1940			}
1941			sort.Slice(recs, func(i, j int) bool {
1942				return recs[i].StartedAt.After(recs[j].StartedAt)
1943			})
1944			writeJSON(w, http.StatusOK, recs)
1945			return
1946		}
1947	
1948		projects := s.state.GetProjects()
1949	
1950		var all []WorkerRecord
1951		seen := map[string]bool{}
1952	
1953		for _, proj := range projects {
1954			var m *WorkerManager
1955			if proj.Path == s.WorkingDir {
1956				m = s.workers
1957			} else {
1958				m = NewWorkerManager(proj.Path)
1959			}
1960			recs, err := m.List()
1961			if err != nil {
1962				continue
1963			}
1964			for _, rec := range recs {
1965				if !seen[rec.ID] {
1966					all = append(all, rec)
1967					seen[rec.ID] = true
1968				}
1969			}
1970		}
1971	
1972		sort.Slice(all, func(i, j int) bool {
1973			return all[i].StartedAt.After(all[j].StartedAt)
1974		})
1975	
1976		writeJSON(w, http.StatusOK, all)
1977	}
